-- ============================================================
-- KGIS Full Migration — Clean slate approach
-- Run on PMS_DB_Dev in SSMS
-- ============================================================

-- STEP 1: Clear old data (safe order)
DELETE FROM PetitionAttachments;
DELETE FROM PetitionWorkflowLogs;
DELETE FROM ActionReports;
DELETE FROM Petitions;
DELETE FROM Taluks;
DELETE FROM Districts;
DBCC CHECKIDENT ('Districts', RESEED, 0);
DBCC CHECKIDENT ('Taluks', RESEED, 0);

-- STEP 2: Add KGIS columns if not exist
IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID('Districts') AND name='KGISCode')
    ALTER TABLE Districts ADD KGISCode NVARCHAR(2) NULL;
IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID('Districts') AND name='NameKN')
    ALTER TABLE Districts ADD NameKN NVARCHAR(100) NULL;
IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID('Taluks') AND name='KGISCode')
    ALTER TABLE Taluks ADD KGISCode NVARCHAR(4) NULL;
IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID('Taluks') AND name='NameKN')
    ALTER TABLE Taluks ADD NameKN NVARCHAR(100) NULL;

-- STEP 3: Create Hoblis table
IF OBJECT_ID('Hoblis','U') IS NOT NULL DROP TABLE Hoblis;
CREATE TABLE Hoblis (
    HobliId    INT IDENTITY(1,1) PRIMARY KEY,
    KGISCode   NVARCHAR(6)   NOT NULL,
    NameEN     NVARCHAR(100) NOT NULL,
    NameKN     NVARCHAR(100) NULL,
    TalukId    INT           NOT NULL,
    DistrictId INT           NOT NULL
);

-- STEP 4: Create Towns table (Urban)
IF OBJECT_ID('Towns','U') IS NOT NULL DROP TABLE Towns;
CREATE TABLE Towns (
    TownId     INT IDENTITY(1,1) PRIMARY KEY,
    KGISTownId INT           NOT NULL,
    KGISCode   NVARCHAR(4)   NOT NULL,
    NameEN     NVARCHAR(100) NOT NULL,
    TownType   NVARCHAR(10)  NULL,
    DistrictId INT           NOT NULL
);

-- STEP 5: Insert Districts (31)
SET IDENTITY_INSERT Districts ON;
SET IDENTITY_INSERT Districts OFF;

-- STEP 6: Insert Taluks (249)
SET IDENTITY_INSERT Taluks ON;
SET IDENTITY_INSERT Taluks OFF;

-- STEP 7: Insert Hoblis (852)

-- STEP 8: Insert Towns (unique, 306)

-- ✅ Done! Verify:
SELECT 'Districts' tbl, COUNT(*) cnt FROM Districts
UNION ALL SELECT 'Taluks', COUNT(*) FROM Taluks
UNION ALL SELECT 'Hoblis', COUNT(*) FROM Hoblis
UNION ALL SELECT 'Towns',  COUNT(*) FROM Towns;